const updateScheduleTimes = `-- name: UpdateScheduleTimes :one
UPDATE machine_schedules
SET
    start_time = $2,
    end_time = $3,
    updated_at = NOW()
WHERE code = $1
    RETURNING id, schedule_date, start_time, end_time, planned_qty, produced_qty, status, sequence, priority_override, notes, created_at, updated_at, machine_code, order_code, code
`

type UpdateScheduleTimesParams struct {
	Code      int64
	StartTime pgtype.Time
	EndTime   pgtype.Time
}

func (q *Queries) UpdateScheduleTimes(ctx context.Context, arg UpdateScheduleTimesParams) (MachineSchedule, error) {
	row := q.db.QueryRow(ctx, updateScheduleTimes, arg.Code, arg.StartTime, arg.EndTime)
	var i MachineSchedule
	err := row.Scan(
		&i.ID,
		&i.ScheduleDate,
		&i.StartTime,
		&i.EndTime,
		&i.PlannedQty,
		&i.ProducedQty,
		&i.Status,
		&i.Sequence,
		&i.PriorityOverride,
		&i.Notes,
		&i.CreatedAt,
		&i.UpdatedAt,
		&i.MachineCode,
		&i.OrderCode,
		&i.Code,
	)
	return i, err
}
